  2	
  3	import { useUniqueEnums } from '@components/common/Filter/useUniqueEnums';
  4	import {
  5	  Badge,
  6	  MenuToggle,
  7	  type MenuToggleElement,
  8	  Select,
  9	  SelectList,
 10	  SelectOption,
 11	  type ToolbarChip,
 12	  ToolbarFilter,
 13	} from '@patternfly/react-core';
 14	import { isEmpty } from '@utils/helpers';
 15	
 16	import type { FilterTypeProps } from './types';
 17	
 18	/**
 19	 * This Filter type enables selecting one or many enum values from the list.
 20	 *
 21	 * **Enum contract**:<br>
 22	 * 1) enum IDs (not translated identifiers) are required to be constant and unique within the enum.<br>
 23	 * 2) the translated labels might be duplicated (one label may map to multiple enum IDs).
 24	 * In such case enums with duplicated labels will be grouped as one option.
 25	 * The common scenario are values not known at the compile time represented by one label i.e. 'Unknown'.
 26	 *
 27	 * **FilterTypeProps are interpreted as follows**:<br>
 28	 * 1) selectedFilters - selected enum IDs.<br>
 29	 * 2) onFilterUpdate - accepts the list of selected enum IDs.<br>
 30	 * 3) supportedValues - supported enum values.
 31	 *
 32	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
 33	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/Filter/EnumFilter.tsx)
 34	 */
 35	export const EnumFilter = ({
 36	  filterId,
 37	  onFilterUpdate: onSelectedEnumIdsChange,
 38	  placeholderLabel,
 39	  resolvedLanguage,
 40	  selectedFilters: selectedEnumIds = [],
 41	  showFilter = true,
 42	  supportedValues: supportedEnumValues = [],
 43	  title = '',
 44	}: FilterTypeProps) => {
 45	  const [isOpen, setIsOpen] = useState(false);
 46	  const { onUniqueFilterUpdate, selectedUniqueEnumLabels, uniqueEnumLabels } = useUniqueEnums({
 47	    onSelectedEnumIdsChange,
 48	    resolvedLanguage,
 49	    selectedEnumIds,
 50	    supportedEnumValues,
 51	  });
 52	
 53	  const deleteFilter = (label: string | ToolbarChip): void => {
 54	    onUniqueFilterUpdate(selectedUniqueEnumLabels.filter((filterLabel) => filterLabel !== label));
 55	  };
 56	
 57	  const hasFilter = (label: string): boolean =>
 58	    Boolean(selectedUniqueEnumLabels.find((filterLabel) => filterLabel === label));
 59	
 60	  const addFilter = (label: string): void => {
 61	    if (typeof label === 'string') {
 62	      onUniqueFilterUpdate([...selectedUniqueEnumLabels, label]);
 63	    }
 64	  };
 65	
 66	  const onToggleClick = () => {
 67	    setIsOpen((prev) => !prev);
 68	  };
 69	
 70	  const onSelect = (_event: ReactMouseEvent | undefined, value: string | number | undefined) => {
 71	    if (hasFilter(value as string)) {
 72	      deleteFilter(value as string);
 73	      return;
 74	    }
 75	    addFilter(value as string);
 76	  };
 77	
 78	  const toggle = (toggleRef: Ref<MenuToggleElement>) => (
 79	    <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen} isFullWidth>
 80	      <>{placeholderLabel}</>
 81	      {!isEmpty(selectedUniqueEnumLabels) && (
 82	        <Badge isRead className="pf-v6-u-ml-sm">
 83	          {selectedUniqueEnumLabels.length}
 84	        </Badge>
 85	      )}
 86	    </MenuToggle>
 87	  );
 88	
 89	  const renderOptions = () => {
 90	    return uniqueEnumLabels.map((label) => (
 91	      <SelectOption
 92	        hasCheckbox
 93	        key={label}
 94	        value={label}
 95	        isSelected={selectedUniqueEnumLabels.includes(label)}
 96	      >
 97	        {label}
 98	      </SelectOption>
 99	    ));
100	  };
101	
102	  return (
103	    <ToolbarFilter
104	      key={filterId}
105	      labels={selectedUniqueEnumLabels}
106	      deleteLabel={(category, option) => {
107	        deleteFilter(option);
108	      }}
109	      deleteLabelGroup={() => {
110	        onUniqueFilterUpdate([]);
111	      }}
112	      categoryName={title}
113	      showToolbarItem={showFilter}
114	    >
115	      {/* This select is different from most and cannot use the common Select */}
116	      {/* eslint-disable-next-line no-restricted-syntax */}
117	      <Select
118	        role="menu"
119	        aria-label={placeholderLabel}
120	        isOpen={isOpen}
121	        selected={selectedUniqueEnumLabels}
122	        onSelect={onSelect}
123	        onOpenChange={(nextOpen: boolean) => {
124	          setIsOpen(nextOpen);
125	        }}
126	        toggle={toggle}
127	        shouldFocusToggleOnSelect
128	        shouldFocusFirstItemOnOpen={false}
129	        isScrollable
130	        popperProps={{
131	          appendTo: document.body,
132	          direction: 'down',
133	          enableFlip: true,
134	        }}
135	      >
136	        <SelectList>{renderOptions()}</SelectList>
137	      </Select>
138	    </ToolbarFilter>
139	  );
140	};

